import { promises as fs } from 'node:fs';
import path from 'node:path';
import { unstable_cache } from 'next/cache';

export type Post = {
  id: string;
  title: string;
  content: string;
  createdAt: string;
};

const postsFilePath = path.join(process.cwd(), 'data', 'posts.json');

async function readPostsFromDisk() {
  const file = await fs.readFile(postsFilePath, 'utf8');
  const posts = JSON.parse(file) as Post[];

  return posts.sort((a, b) => b.createdAt.localeCompare(a.createdAt));
}

export const getPosts = unstable_cache(readPostsFromDisk, ['posts-list'], {
  tags: ['posts']
});

export async function createPost(input: { title: string; content: string }) {
  const posts = await readPostsFromDisk();
  const post: Post = {
    id: crypto.randomUUID(),
    title: input.title,
    content: input.content,
    createdAt: new Date().toISOString()
  };

  await fs.writeFile(postsFilePath, JSON.stringify([post, ...posts], null, 2) + '\n');

  return post;
}

'use server';

import { updateTag } from 'next/cache';
import { redirect } from 'next/navigation';
import { createPost } from '@/lib/posts';

export async function createPostAction(formData: FormData) {
  const title = formData.get('title');
  const content = formData.get('content');

  if (typeof title !== 'string' || typeof content !== 'string') {
    throw new Error('Title and content are required.');
  }

  const trimmedTitle = title.trim();
  const trimmedContent = content.trim();

  if (!trimmedTitle || !trimmedContent) {
    throw new Error('Title and content are required.');
  }

  await createPost({
    title: trimmedTitle,
    content: trimmedContent
  });

  updateTag('posts');
  redirect('/');
}

